final:
module RefModule
    (
        input clk,
        input load,
        input [3:0] din,
        output reg [3:0] q
    );

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
    begin
        if (load)
            q <= din;
        else
            q <= {q[2:0], 1'b0};
    end

endmodule
